#!/usr/bin/env python3
"""
MKT Original Commentary — Ecclesiastes chapters 5–9 (96 verses)
Run: python3 scripts/zc-original-ecclesiastes-5-9-full.py

Source data:
- data/interlinear/ecclesiastes.json
- data/translation/draft/mediating/ecclesiastes.json

Key term decisions (continuing from chs 1–4):
- hevel: "vapor/futility" — continues 38-occurrence pattern
- yitron: "lasting gain/profit" — appears in 6:8; 7:11; 10:10
- amal: toil (activity) and its fruit — both senses active
- miqreh: "fate/event" — the common lot, heavy in ch 9
- helqi/helqo: "portion" — carpe diem counsel; appears in 5:18; 9:9
- simha: "joy" — positive counsel term; appears in 5:20; 8:15; 9:7
- nefesh: "soul/appetite/life" — primarily as appetite in chs 5–6

New terms in chs 5–9:
- neder (H5088): vow — 5:2,4,5; serious commitment language
- inyan (H6045): unhappy business/occupation — recurs in 5:3,13
- pith'gam (H6599): verdict/sentence — Aramaic loanword at 8:11
- shem (H8034): name/reputation — 7:1 wordplay with shemen (oil)
- tzadiq (H6662): righteous — destabilized in 7:15–16 and 9:2
- ma'aneh (H6039): preoccupation/occupation — God's gift of joy at 5:20
- mishpat (H4941): justice/judgment — denied in 5:8; known by wise at 8:5–6
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ECCLESIASTES = {
    "5": {
        "1": "<p><strong>Shomer raglekha ka'asher telekh el-beit ha'Elohim</strong> — 'Guard your steps when you go to the house of God.' The verb <em>shamar</em> (to guard/keep) carries covenant weight — it is the word used for keeping the commands (Exod 20:6) and guarding the garden (Gen 2:15). The feet represent one's approach and posture. <em>Qarov lishmo'a tov mi-teit ha-kesil zebakh</em> — 'to draw near to listen is better than to offer the sacrifice of fools.' The comparison inverts the expected liturgical priority: attentive hearing precedes offering. <em>Ki einam yod'im la'asot ra'</em> — 'who do not realize they are doing wrong' — literally 'who do not know to do evil,' an ironic formula: the fool's sacrifice is evil precisely because it proceeds without hearing.</p>",
        "2": "<p><strong>Al temaher al-pikha</strong> — 'Do not be hasty with your words.' The verb <em>bahal</em> (H926, to be hasty/dismayed/terrified) is a strong word: it suggests being swept away by impulse. <em>Ve-libekha al yemaher lehozi dabar lifnei ha'Elohim</strong> — 'do not be quick in your heart to speak before God.' The heart (<em>lev</em>) is the organ of intention and deliberation; the Teacher's concern is with the inner disposition that produces hasty speech, not just the speech itself. <em>Ki ha'Elohim bashamayim ve'atah al-ha'aretz</em> — 'for God is in heaven and you are on earth' — the spatial asymmetry establishes the asymmetry of the relationship. <em>Al-ken yih'yu devarekha me'atim</em> — 'so let your words be few' — restraint as the appropriate creaturely response to the Creator's transcendence.</p>",
        "3": "<p><strong>Ki ba hachalot be-rov inyan</strong> — 'For a dream comes from too many concerns.' <em>Rov inyan</em> (too many concerns/business) — the word <em>inyan</em> (H6045, business/preoccupation) recurs from 1:13; here it generates the unsettled sleep that produces dreams. <em>Ve-qol ha-kesil be-rov devarim</em> — 'and a fool's chatter from too many words.' The parallel structure is precise: as many concerns → dream, so many words → foolish speech. Both are signs of a mind not at rest. The implication of the comparison: the fool's excessive speech is the waking equivalent of meaningless dreaming — activity without content.</p>",
        "4": "<p><strong>Ka'asher tidar neder la'Elohim al-te'acher leshalemo</strong> — 'When you make a vow to God, do not delay in fulfilling it.' The noun <em>neder</em> (H5088, vow) is a solemn promise made to God, typically conditional ('if you do X, I will do Y' — cf. Gen 28:20-22; Num 30:2; Deut 23:21-23). The specific prohibition against delay picks up Deut 23:21: 'If you make a vow to YHWH your God, do not delay fulfilling it.' <em>Ki ein chafetz ba-kesiylim</em> — 'for he takes no pleasure in fools.' The verb <em>chafatz</em> (to delight/take pleasure in) is the covenant word for God's delight in his people (Ps 18:19; Isa 62:4). Its negation here is severe: the fool who makes and fails to keep a vow has forfeited the possibility of divine delight.</p>",
        "5": "<p><strong>Tov asher lo-tidor mishtidar ve-lo teshalem</strong> — 'It is better not to vow than to vow and not fulfill it.' The <em>tov min</em> (better than) comparative form appears frequently in ch 7; here it appears in the vow instruction as the pragmatic conclusion: the lesser obligation (no vow) is preferable to the greater broken obligation. Deuteronomy 23:22 states explicitly: 'If you refrain from vowing, it will not be sin to you' — the Teacher cites this practical wisdom directly. The structure of the statement is a Solomonic legal clarification: it does not encourage vow-making, but sets the threshold for integrity when a vow is made.</p>",
        "6": "<p><strong>Al-titein et-pikha lachati et-besarekha</strong> — 'Do not let your mouth lead your flesh into sin.' The unusual phrase <em>lachati et-besarekha</em> (to make your flesh sin) suggests that the consequences of rash vow-making reach beyond the speaker to their whole person. <em>Ve-al-tomar lifnei ha-malakh ki shegagah hi</em> — 'and do not tell the priest it was a mistake.' The word <em>malakh</em> (messenger/angel) here refers to the cultic priest (cf. Mal 2:7: the priest as God's messenger). The post-hoc rationalization ('I didn't mean it') is the specific danger the Teacher addresses. <em>Lamah yiqtzof ha'Elohim al qolekha</strong> — 'Why should God be angry at your words?' The verb <em>qatsaf</em> (to be angry/wrathful) describes the serious divine response to vow-breaking (Num 30:2; Deut 23:21).</p>",
        "7": "<p><strong>Ki be-rov chalomot vahalim u-devarim harbeh</strong> — 'When there are many dreams, there are futile words aplenty.' <em>Havalim</em> is the plural of <em>hevel</em>: the connection is explicit — many dreams, many words, are manifestations of the book's central category of futility. The instruction ends with two Hebrew words: <em>ki et-ha'Elohim yera</em> — 'fear God.' This two-word conclusion is the compressed positive instruction: after the extended warning about vows and rash words, the positive command is the simplest possible — reverential awe before God. The <em>yir'at Elohim</em> (fear of God) is the foundation of wisdom (Prov 1:7) and the repeated counsel throughout Ecclesiastes (3:14; 5:7; 7:18; 8:12-13; 12:13).</p>",
        "8": "<p><strong>Im chamas rash ve-gezel mishpat va-tzedek tir'eh ba-medinah</strong> — 'If you see the poor being oppressed and justice and equity denied in a district.' <em>Chamas</em> (H2555, violence/oppression) and <em>gezel</em> (H1500, robbery/extortion) describe two forms of social wrongdoing; <em>mishpat va-tzedek</em> (justice and righteousness) are the pillars of YHWH's throne (Ps 89:14) now denied to the poor. <em>Al-titamah al-ha-chefetz</em> — 'do not be surprised at the matter' — <em>tamah</em> (to be amazed/astonished). The explanation follows: <em>ki gavohah me'al gavohah shomer</em> — 'for one official is covered by a higher one' — a bureaucratic hierarchy where each level provides cover for the level below. The Teacher is describing systemic corruption, not individual evil.</p>",
        "9": "<p><strong>Ve-yitron eretz ba-kol hi melekh le-sadeh ne'evad</strong> — 'Yet in all this, there is an advantage that belongs to everyone: even a king is served by the cultivated land.' This verse is one of the most contested in Ecclesiastes — the Hebrew is compressed and the interpretations numerous. The MKT reads it as a grounding observation: despite bureaucratic oppression (v.8), the land itself remains the source of sustenance for all, including the king. The agricultural basis of all wealth means that even the highest level of the corrupt hierarchy depends on the same soil that serves the lowest. The <em>yitron</em> here (advantage) is not the ultimate <em>yitron</em> the Teacher has been seeking, but a practical sufficiency — the earth provides for all.</p>",
        "10": "<p><strong>Ohev kesef lo-yisba kesef</strong> — 'Whoever loves money is never satisfied with money.' <em>Ohev</em> (H157, lover/one who loves) — the same root as the covenant love word <em>ahavah</em>; here it describes disordered attachment. The insatiability of the money-lover connects back to the sea that is 'never full' (1:7) and the eye 'not satisfied' (1:8): the same structure of endless appetite that defines the under-the-sun condition. <em>Mi-ohev be-hamon lo-tevu'ah</em> — 'whoever loves wealth is never satisfied with income' — <em>hamon</em> (abundance/crowd/wealth) and <em>tevu'ah</em> (income/produce): wealth in quantity and wealth in flow both fail to satisfy. <em>Gam-zeh havel</em> — 'this too is vapor' — the brief verdict.</p>",
        "11": "<p><strong>Be-robh hatovah rabhu okheleyha</strong> — 'As goods increase, so do those who consume them.' The accumulation of goods attracts its own set of consumers — servants, dependents, family, hangers-on — so that the net benefit to the owner diminishes as the gross wealth increases. <em>U-mah-kisron le-vaalah ki im-re'iyat einav</em> — 'what benefit remains for the owner beyond seeing them with his own eyes?' The only genuine benefit of accumulated wealth is the visual experience of possessing it. <em>Kisron</em> (H3666, advantage/profit) — related to <em>kishron</em> (skill) and <em>yitron</em>; a word unique to Ecclesiastes. The bitter irony: the owner's only gain from growing wealth is looking at it.</p>",
        "12": "<p><strong>Metukah shnat ha'aved im-me'at ve-im-harbeh yokhal</strong> — 'The sleep of the laborer is sweet, whether he eats little or much.' The word <em>metukah</em> (H4966, sweet) is sensory — the sleep is genuinely enjoyable, not merely the absence of insomnia. <em>Ve-hasava le'ashir einennu meniyach lo lishon</em> — 'but the excess of wealth allows the rich man no sleep.' The word <em>sava</em> (H7647, satiety/excess) connects back to the insatiable eye and ear (1:8) and the sea (1:7): too much wealth creates the same structural insatiability. The social irony: the laborer who has little sleeps sweetly; the wealthy man who has too much cannot sleep. Abundance is a burden, not a rest.</p>",
        "13": "<p><strong>Yesh ra'ah cholah ra'iti tahat hashemesh</strong> — 'Here is a grievous evil I have observed under the sun.' The adjective <em>cholah</em> (H2470, sick/grievous) intensifies <em>ra'ah</em> (evil) — this is not merely bad but sickening evil. The phrase <em>ra'ah cholah</em> is a Ecclesiastes formula for the worst category of bad outcome (also 5:16; 6:2). <em>Osher shamur li-v'alav le-ra'ato</em> — 'wealth hoarded by its owner at his own expense' — the prepositional phrase <em>le-ra'ato</em> ('to his own harm/evil') is the paradox: the hoarded wealth designed to benefit the owner destroys him instead.</p>",
        "14": "<p><strong>Ve-abad ha-osher hahu be-inyan ra'</strong> — 'Those riches were lost in a bad venture.' <em>Inyan ra'</em> (H6045 + H7451, bad business/evil affair) — the same <em>inyan</em> word used for the 'unhappy business' God gives to humanity (1:13): bad business can describe both God's assignment of existence and the specific bad investment that loses the wealth. <em>Ve-holid ben ve-ein be-yado me'umah</em> — 'and he had fathered a son, but had nothing to leave him.' The word <em>ben</em> (son) triggers the inheritance problem of 2:18-21: a son exists but has nothing to inherit. The wealthy man's failure leaves his son as destitute as the stillborn child who receives no inheritance.</p>",
        "15": "<p><strong>Ka'asher yatza mi-beten immo arumm yashuv laleshet ke-shehar ba</strong> — 'As he came from his mother's womb, so he will leave — naked.' The wordplay: <em>arumm</em> (naked) echoes the nakedness of Adam and Eve (Gen 2:25; 3:7, 10-11) — the human's fundamental condition before the fall and at death. <em>U-me'umah lo-yisa ba'amalo</em> — 'he can take nothing for his labor that he could carry in his hand.' <em>Amal</em> here in both senses: the activity and its fruit. The man's hands — the organs of his labor — go empty into death. The connection to Job 1:21 ('naked I came from my mother's womb, and naked I shall return') places this observation in a long wisdom tradition about death's radical dispossession.</p>",
        "16": "<p><strong>Ve-gam-zot ra'ah cholah</strong> — 'This too is a grievous evil.' The formula reinforces the category: the naked departure (v.15) is evaluated with the same <em>ra'ah cholah</em> judgment as the hoarded wealth. <em>Ke-khol-shevar ken yelekh</em> — 'just as he came, so he goes' — the exact parallel of birth-departure. <em>U-mah-yitron lo she-yamal la-ruach</em> — 'what does anyone gain who labors for the wind?' <em>Yitron</em> reappears: the accumulator who goes naked into death has achieved zero net advantage — all the labor has been for wind (<em>la-ruach</em>), the same word as in 'chasing the wind' but now as the destination of labor rather than its futile pursuit.</p>",
        "17": "<p><strong>Gam kol-yamav ba-choshekh yokhal</strong> — 'Throughout his days he eats in darkness.' <em>Ba-choshekh</em> (in darkness) — not literal night but the metaphorical darkness of joylessness and anxiety. The laborer of v.12 sleeps sweetly; the rich man of v.17 eats in darkness. <em>Ve-cha'as harbeh ve-choli ve-qa'as</em> — 'burdened with much sickness, vexation, and anger.' <em>Ka'as</em> (H3708, vexation/frustration) appears at 1:18 for the sorrow that accompanies increased knowledge; here it describes the existential condition of the anxiety-ridden accumulator. The three-fold burden (sickness, vexation, anger) is the experiential reality behind the <em>ra'ah cholah</em> verdict.</p>",
        "18": "<p><strong>Hineh asher ra'iti ani tov asher yafeh le'echol ve-lishtot</strong> — 'This is what I have found to be good and fitting.' The word <em>yafeh</em> (H3303, beautiful/fitting/appropriate) — the same root as 'he has made everything beautiful in its time' (3:11). The carpe diem positive counsel is framed with the same aesthetic category as God's creative ordering: the appropriate enjoyment of food, drink, and labor is beautiful — a fit response to existence. <em>Ki hu-helqo</em> — 'for that is one's portion' — <em>helq</em> reappears (cf. 2:10; 3:22): the portion that genuinely belongs to the person. The alternative of anxious hoarding destroys the capacity for the <em>helq</em> that is actually available.</p>",
        "19": "<p><strong>Gam kol-ha'adam asher natan-lo ha'Elohim osher u-nekhasim</strong> — 'Furthermore, when God gives someone wealth and possessions.' The distinction between vv.13-17 and v.19 is crucial: v.13's <em>osher shamur</em> is wealth hoarded; v.19's <em>osher u-nekhasim</em> is wealth given by God and enjoyed. <em>Ve-hishilto le'ekhol mimmennu u-lasehet helqo</em> — 'and enables him to enjoy these things — to accept his portion.' The verb <em>shalat</em> (to have power over/control) is used of dominion (cf. 2:19): here God grants the person power over their own wealth to enjoy it. <em>Ki hu mattanat Elohim hi</em> — 'that is a gift of God.' The word <em>mattat</em> (H4991, gift) — from <em>natan</em> (to give): the capacity for enjoyment is divinely donated, the direct opposite of anxiety-driven accumulation.</p>",
        "20": "<p><strong>Ki lo harbeh yizkor et-yemei chayyav</strong> — 'Such a person will not brood much over the years of their life.' <em>Yizkor</em> (H2142, to remember/call to mind) — the person who enjoys their portion does not obsessively rehearse the past or calculate the future. <em>Ki ha'Elohim ma'aneh be-simhat libbo</em> — 'because God keeps their heart occupied with joy.' The hapax <em>ma'aneh</em> (H6039, preoccupation/the thing that occupies/answers) derives from <em>anah</em> (to answer/respond/be occupied with). God does not merely grant joy as an occasional gift; he fills the person's heart with it as an ongoing occupation. The word's root meaning (to answer/respond) suggests that joy is God's ongoing answer to the question of meaning that the <em>hevel</em>-saturated world poses.</p>"
    },
    "6": {
        "1": "<p><strong>Yesh ra'ah asher ra'iti tahat hashemesh ve-rabbah hi al-ha'adam</strong> — 'There is an evil I have observed under the sun, and it is widespread among human beings.' The Teacher introduces a new case study with his characteristic empirical formula (<em>ra'iti</em>, I have seen). <em>Ve-rabbah hi al-ha'adam</em> — 'it is widespread/heavy upon people' — the adjective <em>rabbah</em> (H7231, great/widespread/heavy) describes both the frequency of the evil and its weight on those who experience it. The evil of ch 6 is more refined than oppression (ch 5): it is the situation of having everything materially and being unable to enjoy any of it.</p>",
        "2": "<p><strong>Ish asher yiten-lo ha'Elohim osher u-nekhasim ve-khavod</strong> — 'Here is a man to whom God gives wealth, riches, and honor.' The triple gift (wealth, riches, honor) is the complete package of material and social blessing. <em>Ve-einennu machsor le-nafsho mi-kol asher yit'aveh</em> — 'so that nothing he desires is lacking.' The word <em>nefesh</em> (H5315) here means appetite/desire — what the soul craves. <em>Ve-lo-yashlitennu ha'Elohim le'ekhol mimmennu</em> — 'yet God does not give him the capacity to enjoy any of it.' The verb <em>shalat</em> (dominion/control) appeared at 5:19 for the one God enables; its negation here is the condition of the man who has everything but the ability to experience it. <em>Ki ish nokri yokhlennu</em> — 'and a stranger devours it all' — the total loss of inheritance, as in 2:18-19 but now the stranger may arrive even before death.</p>",
        "3": "<p><strong>Im-yolid ish meah ve-shanim rabbat yich'yeh</strong> — 'A man may father a hundred children and live a long life.' The extremes of apparent blessing: one hundred children (far beyond the patriarchal ideal) and many years. <em>Ve-nefesh lo-tisbah min-hatovah</em> — 'yet if he cannot fill himself with good things' — <em>sava</em> (to be satisfied/full) with the good: the insatiability from 1:7-8 reappears. <em>Ve-gam-keverah lo-hayta lo</em> — 'and in the end receives no burial' — burial denial was in the ANE the ultimate dishonor; it meant no memorial, no rites, no continuing presence in the community's memory. Even with one hundred children and long life, without enjoyment and without proper burial, the stillborn (<em>nefesh</em>) fares better.</p>",
        "4": "<p><strong>Ki be-hevel ba u-ve-choshekh yelekh</strong> — 'For the stillborn comes in vapor and departs in darkness.' <em>Be-hevel ba</em> — 'comes in <em>hevel</em>' — the stillborn's brief, breath-like existence is itself an instance of <em>hevel</em>. <em>U-ve-choshekh yelekh</em> — 'and goes in darkness' — the stillborn never sees light (v.5). <em>U-ve-choshekh shemo yekhuseh</em> — 'and its name is buried in darkness' — <em>shemo yekhuseh</em> (its name is covered/buried) echoes the memorial concern of 1:11: no <em>zikaron</em>, no name, no memory. The stillborn's condition is the Teacher's standard for ultimate deprivation — and even this is better than the man with one hundred children who cannot enjoy them.</p>",
        "5": "<p><strong>Gam-shemesh lo-ra'ah ve-lo yada</strong> — 'It has never seen the sun or known anything.' The stillborn's deprivations accumulate: no light, no knowledge, no experience. <em>Nachath la-zeh min-zeh</em> — 'yet it finds more rest than the other.' The word <em>nachath</em> (H5183, rest/contentment) appeared at 4:6 for the one hand of quietness that is better than two hands of toil. The stillborn's total deprivation paradoxically constitutes rest — it has escaped the impossible burden of having everything without the capacity to enjoy it.</p>",
        "6": "<p><strong>Ve-ilu chayah alef shanim pa'amayim ve-tovah lo ra'ah</strong> — 'Even if that man were to live two thousand years and yet find nothing good.' The two-thousand-year hypothetical extends the failure to its maximum possible term: not one hundred children and many years, but two thousand years — and still no enjoyment. <em>Halo el-maqom echad haKol holekh</em> — 'does not everyone go to the same place in the end?' The rhetorical question returns to the <em>maqom echad</em> (one place) of 3:20 — death as the universal destination that erases the distinction between the advantaged and the disadvantaged. Even two thousand years without enjoyment converge on the same terminus as a brief life with it.</p>",
        "7": "<p><strong>Kol-amal ha'adam le-fihu ve-gam ha-nefesh lo timale</strong> — 'All of a person's labor goes toward filling the mouth, yet the appetite is never satisfied.' <em>Le-fihu</em> (for his mouth) — the mouth as the primary organ of consumption; all labor is directed toward the basic act of eating. <em>Ha-nefesh lo timale</em> — 'the appetite is never satisfied' — <em>nefesh</em> here in its appetite sense (as in 6:2). The same <em>sava</em>/fullness that the sea never reaches (1:7) and the eye never achieves (1:8) now describes the appetite's fundamental insatiability. The structure is circular: labor feeds the mouth, the mouth drives more labor, the appetite is never filled.</p>",
        "8": "<p><strong>Ki mah-yitron le-chakham min-ha-kesil</strong> — 'What real advantage does the wise person have over the fool?' <em>Yitron</em> recurs in its comparative form: if the appetite of both wise and fool is equally insatiable, and if both die the same death, what does wisdom's advantage amount to? <em>Mah-le'ani yode'a lahalekh neged ha-chayyim</strong> — 'and what does the poor person gain from knowing how to navigate life?' The phrase <em>lahalekh neged ha-chayyim</em> (to walk before/against the living, or to navigate life) is a practical wisdom phrase: even the practical skill of survival in society produces no lasting advantage for the poor person. The question undercuts any easy equation of wisdom with success.</p>",
        "9": "<p><strong>Tov mar'eh einayim mi-halokh-nefesh</strong> — 'Better what the eyes can actually see than the restless wandering of desire.' <em>Mar'eh einayim</em> (what the eyes see) — the immediate, present experience. <em>Halokh nefesh</em> (wandering of the soul/desire) — the restless movement of appetite toward what is not possessed. The <em>tov min</em> comparison counsels present enjoyment over restless desire: what is actually before one is better than what desire drives one toward. <em>Gam-zeh hevel u-re'ut ruach</em> — the full verdict formula. Even this observation — and the practical wisdom it contains — falls under the <em>hevel</em> category within the under-the-sun frame.</p>",
        "10": "<p><strong>Mah-shehayah kebar niqra shemo</strong> — 'Whatever exists has already been named.' The naming of what exists picks up Gen 2:19-20 (Adam naming the animals) — to be named is to be placed within the created order. <em>Ve-noda asher-hu adam</em> — 'it is known what a human being is' — the essence of the human (<em>adam</em>) is already established; there is no novelty in the human condition. <em>Ve-lo yuchal ladin im sheteqef mimmennu</em> — 'and no one can contend with one far more powerful.' The word <em>teqef</em> (H8624, more powerful/stronger) likely refers to God — the human cannot dispute with the One who has established the order. This is the epistemic limit of 'under the sun' existence: the order is given, not negotiable.</p>",
        "11": "<p><strong>Ki yesh-devarim harbeh marbim havel</strong> — 'The more words there are, the more futility.' <em>Marbim havel</em> (multiplying <em>hevel</em>) — the paradox: the more one speaks to explain existence, the more futility is generated. The Teacher has been speaking at length about futility; even his own commentary participates in the multiplication of <em>hevel</em>-words. <em>Mah-yoter le'adam</em> — 'what benefit is there for a person?' The question leaves the reader precisely where the Teacher intends: without a satisfying answer within the 'under the sun' frame.</p>",
        "12": "<p><strong>Ki mi yode'a mah-tov le'adam ba-chayyim</strong> — 'For who knows what is truly good for a person in life?' The <em>mi yode'a</em> ('who knows?') formula marks the epistemological limit of this section. <em>Mispar yemei-chayyei havlecha</strong> — 'during all those fleeting days' — literally 'the number of the days of his vapor-life.' The genitival phrase <em>chayyei havlecha</em> (the life of your vapor/futility) is striking: life itself is characterized as <em>hevel</em> — not the individual moments but the whole of existence under the sun. <em>Ve-ashem yagid le-adam mah-yihyeh acharav tahat hashemesh</em> — 'and who can tell anyone what will happen under the sun after they are gone?' The double limitation: no one knows what is good now; no one knows what will happen after. The epistemological frame of 'under the sun' wisdom is completely closed from both ends.</p>"
    },
    "7": {
        "1": "<p><strong>Tov shem mi-shemen tov</strong> — 'A good name is better than fine perfume.' The wordplay is precise in Hebrew: <em>shem</em> (name) and <em>shemen</em> (oil/perfume) are near-homophones that differ by one letter. The comparison inverts commercial value: expensive oil (<em>shemen tov</em>) is materially costly, but a good reputation (<em>shem tov</em>) surpasses it. The name/reputation (<em>shem</em>) is the intangible memorial that outlasts death; oil is consumed in use. <em>Ve-yom ha-mavet mi-yom hivvaledo</em> — 'and the day of death than the day of birth.' The provocative comparison: at death, the name is established and its verdict known; at birth, it is uncertain. The day of death is the completion of the narrative that birth only begins.</p>",
        "2": "<p><strong>Tov lalekhet el-beit evel mi-lalekhet el-beit mishteh</strong> — 'It is better to go to a house of mourning than to a house of feasting.' The <em>tov min</em> comparison appears at the start of a series that runs through ch 7. <em>Beit evel</em> (house of mourning) vs <em>beit mishteh</em> (house of feasting/drinking) — the two poles of social gathering. <em>Hu sof kol-ha'adam ve-ha-chai yiten el-libbo</em> — 'for death is the end of every person, and the living should take it to heart.' The phrase <em>yiten el-libbo</em> (set/give it to his heart) means to internalize, to take seriously into one's deliberative center. The house of mourning is educationally superior because it confronts the visitor with the truth about mortality that the house of feasting conceals.</p>",
        "3": "<p><strong>Tov ka'as mi-skhok</strong> — 'Sorrow is better than laughter.' The word <em>ka'as</em> (H3708, vexation/grief/sorrow) appeared at 1:18 and 5:17 for the pain that wisdom and anxiety produce; here it is the word for the productive grief of the mourning house. <em>Ki-be-ro'a fanim yitav lev</em> — 'for a sad face does the heart good.' The paradox: the face that shows sorrow (<em>ro'a fanim</em>, literally 'evil/bad face') benefits the heart. The <em>lev</em> (heart) that is educated by grief is better prepared for reality than the heart that has only experienced laughter's avoidance of it.</p>",
        "4": "<p><strong>Lev chakhamim be-beit evel ve-lev kesilim be-beit simha</strong> — 'The heart of the wise is drawn to the house of mourning, but the heart of fools to the house of mirth.' The wisdom/foolishness distinction is made by what the heart is drawn toward — wisdom gravitates toward the instructive (mourning), folly toward the pleasant (mirth). <em>Simha</em> (joy) — the word used for God's positive gift throughout the book — here, when it is the fool's destination rather than God's gift, it marks the difference between joy as appropriate response and joy as avoidance strategy.</p>",
        "5": "<p><strong>Tov lishmo'a ga'arat chakham mi-ish shome'a shir kesilim</strong> — 'It is better to hear the rebuke of the wise than to hear the song of fools.' The word <em>ga'arat</em> (H1606, rebuke/reproof) is the severe verbal correction that wisdom offers. It contrasts with <em>shir kesilim</em> (the song of fools) — pleasurable but vacuous. The same structure as v.2's mourning/feasting contrast: what is unpleasant and instructive is better than what is pleasant and empty. The rebuke (<em>ga'arah</em>) is the verbal equivalent of the house of mourning.</p>",
        "6": "<p><strong>Ki ke-qol ha-sirim tahat ha-sir ken skhok ha-kesil</strong> — 'For like the crackling of thorns under a pot, so is the laughter of a fool.' The word <em>sirim</em> (thorns) and <em>sir</em> (pot) are another Hebrew near-homophone pair — the crackling sound of dry thorns as fuel and the pot they heat. Thorns are quick to light, loud in burning, and consumed rapidly without producing lasting heat or coals. The fool's laughter (<em>skhok ha-kesil</em>) has the same character: it is showy, brief, and leaves nothing useful behind. <em>Gam-zeh havel</em> — the verdict applied to foolish laughter specifically.</p>",
        "7": "<p><strong>Ki ha'oshek yeholel chakham</strong> — 'Surely oppression makes a fool of a wise man.' The verb <em>halal</em> (piel: to make mad/drive to foolishness) — the same root as <em>mehulal</em> in 2:2 (madness of laughter). Oppression is not merely a social wrong; it corrupts the mind of the one subjected to it. <em>U-yabbed mattanah et-halev</em> — 'and a bribe corrupts the heart.' <em>Abad</em> (to destroy/ruin) in the piel means to make perish — the bribe does not merely bend the heart but destroys its capacity for wisdom. The two corrupting forces — oppression and bribery — represent external coercion and internal corruption.</p>",
        "8": "<p><strong>Tov acharit davar me-reshito</strong> — 'The end of a matter is better than its beginning.' <em>Acharit</em> (H319, end/outcome/latter) vs <em>reshit</em> (beginning/first): the observation about temporal priority — what comes last is better than what comes first, because the end reveals what the beginning only promised. <em>Tov erekh-ruach mi-gevah-ruach</em> — 'and patience of spirit is better than pride of spirit.' <em>Erekh-ruach</em> (H750+H7307, long of spirit/slow to anger/patient) vs <em>gevah-ruach</em> (H1361+H7307, high of spirit/proud/arrogant). The same word <em>ruach</em> (spirit) describes both: patience is the spirit stretched out over time; pride is the spirit puffed up in the moment.</p>",
        "9": "<p><strong>Al-temaher be-ruchakha likhtsos</strong> — 'Do not be hasty in your spirit to become angry.' <em>Bahal</em> (hasty/dismayed) reappears from 5:2; <em>khas</em> (H3707, to be angry/vexed) — the prompt anger that springs from pride (v.8). <em>Ki ka'as be-cheq kesilim yanuach</em> — 'for anger rests in the lap of fools.' <em>Ka'as</em> (anger/vexation) — the word oscillates between productive grief (7:3) and destructive anger (7:9); the difference is contextual. Here it is the quick temper that lives permanently in the fool's lap — not an occasional visitor but a resident. The word <em>yanuach</em> (to rest/settle) ironically describes anger as having found its home in the fool.</p>",
        "10": "<p><strong>Al-tomar mah hayah she-hayamim ha-rishonim hayu tovim me'elleh</strong> — 'Do not say, &#8220;Why were the former days better than these?&#8220;' The nostalgic question is identified as unwise. <em>Ki lo me-chakhmah sha'alta al-zeh</em> — 'for it is not from wisdom that you ask this.' The Teacher does not say the past was not better — he says that asking the question is itself an index of foolishness, not wisdom. Wisdom accepts the structure of appointed times (ch 3) and takes the present season as the context for action, not as something to be compared unfavorably with an idealized past.</p>",
        "11": "<p><strong>Tovah chakhmah im-nachalah</strong> — 'Wisdom, like an inheritance, is a good thing.' <em>Im-nachalah</em> (with/like an inheritance) — the comparison is syntactically ambiguous: is wisdom better when combined with an inheritance, or is wisdom as good as an inheritance? The MKT reads it as a comparison: wisdom has the kind of value that a material inheritance has — a secure possession that benefits its holder over time. <em>Ve-yoter le-ro'ei ha-shemesh</em> — 'it benefits those who see the sun.' <em>Yoter</em> (H3148, advantage/profit) — related to <em>yitron</em>; another profit word. Wisdom provides a genuine advantage for those alive under the sun — not ultimate <em>yitron</em>, but real relative benefit.</p>",
        "12": "<p><strong>Ki be-tzel ha-chakhmah be-tzel ha-kesef</strong> — 'For wisdom protects just as money protects.' <em>Be-tzel</em> (in the shade/shadow of) — protection from the sun, figuratively protection in general. Both wisdom and money offer shelter (<em>tzel</em>). <em>Ve-yitron da'at ha-chakhmah techayyeh be'aleyha</em> — 'but the advantage of knowledge is that wisdom preserves the life of its possessor.' The word <em>techayyeh</em> (gives life/preserves life) from <em>chayah</em> (to live) — wisdom has the quality of life-preservation that money alone does not. <em>Yitron da'at</em> (the advantage/profit of knowledge) — here a genuine, not merely rhetorical, <em>yitron</em>: within the under-sun frame, wisdom extends and preserves life in a way money cannot guarantee.</p>",
        "13": "<p><strong>Re'eh et-ma'aseh ha'Elohim</strong> — 'Consider what God has done.' The imperative <em>re'eh</em> (see/consider) is the Teacher's characteristic call to empirical attention — but now directed not at accumulated goods or social structures, but at God's work specifically. <em>Ki mi-yuchal letaqqen et asher ivvato</em> — 'who can straighten what he has made crooked?' The verb <em>taqan</em> (to straighten) from 1:15: what was declared impossible for humans ('what is crooked cannot be made straight') is now attributed to God's making. God has made some things crooked — this is the theodicy realism of Ecclesiastes. The Teacher does not explain why; he simply identifies it as God's doing and counsels acceptance.</p>",
        "14": "<p><strong>Be-yom tovah heyeh be-tovah</strong> — 'In good times, enjoy what you have.' The imperative <em>heyeh</em> (be) with the prepositional <em>be-tovah</em> (in goodness): do not spend good times worrying about bad times to come. <em>U-ve-yom ra'ah re'eh</em> — 'but in bad times consider this' — the same <em>re'eh</em> (observe/consider) as v.13. <em>Gam et-zeh le-umat-zeh asah ha'Elohim</em> — 'God has made both the one and the other.' God is the maker of both good times and bad (cf. Isa 45:7: 'I form light and create darkness; I make peace and create calamity'). <em>Al-divrat she-lo yimtza ha'adam acharav me'umah</em> — 'so that no one can discover what the future holds.' The divine ordering of alternating good and bad serves an epistemological purpose: it prevents the human from predicting and controlling the future.</p>",
        "15": "<p><strong>Et-hakol ra'iti bi-mei havli</strong> — 'In my futile days I have seen everything.' <em>Bi-mei havli</em> (in my days of vapor) — the Teacher's life itself is characterized as <em>hevel</em>. <em>Yesh tzadiq oved be-tzidqo</em> — 'a righteous man perishing in his righteousness.' <em>Tzadiq</em> (H6662, righteous) — the person whose life conforms to moral and covenant norms. Their perishing (<em>aved</em>) in their very righteousness inverts the retribution principle that wisdom normally affirms (Prov 11:19; 12:28). <em>Ve-yesh rasha ma'arikh be-ra'ato</em> — 'a wicked man living long in his wickedness.' <em>Ma'arikh</em> (lengthening, from <em>arak</em>) — the wicked person's life is extended, precisely when Proverbs says it should be cut short. The Teacher does not rationalize; he observes the empirical datum and lets it stand.</p>",
        "16": "<p><strong>Al-tehe tzadiq harbeh</strong> — 'Do not be excessively righteous.' This verse is among the most debated in Ecclesiastes. The Teacher is not commending sin; he is warning against a particular kind of rigid, self-congratulatory righteousness that makes excessive claims. <em>Ve-al-titchakkem yoter</em> — 'and do not make yourself overly wise.' The reflexive <em>titchakkem</em> (making yourself wise) suggests performance of wisdom rather than its genuine possession. <em>Lamah tishshomem</em> — 'why should you ruin yourself?' — <em>shamaim</em> (to be desolate/ruined): the person who plays at extremes of righteousness destroys themselves. Verse 16 and v.17 together frame a middle path: neither excessive moralism (v.16) nor excessive wickedness (v.17).</p>",
        "17": "<p><strong>Al-tirsha harbeh ve-al-tehi sakal</strong> — 'Do not be excessively wicked, and do not be a fool.' The parallel with v.16 is structural: just as excessive righteousness destroys, so does wickedness. <em>Lamah tamut be-lo itecha</em> — 'why die before your time?' The phrase <em>be-lo itekha</em> (before your time) — literally 'not in your time' — implies that death has its own appointed time (<em>et</em>), and premature death by wickedness violates that structure. Together vv.16-17 describe the two paths of destruction: one is the pretense of virtue carried to self-destructive excess; the other is unrestrained wickedness.</p>",
        "18": "<p><strong>Tov asher tochaz be-zeh</strong> — 'It is good to grasp the one and not release the other.' Both the moderate righteousness of v.16 and the avoidance of wickedness of v.17 are to be held simultaneously. <em>Ki-yere Elohim yetze et-kulam</em> — 'for the one who fears God will avoid both extremes.' The <em>yir'at Elohim</em> (fear of God) is the practical navigational principle: reverence before God orients the person away from both the self-destruction of excessive moralism and the self-destruction of wickedness. The fear of God is the stable center between the two destructive poles.</p>",
        "19": "<p><strong>Ha-chakhmah ta'oz la-chakham me'asarah shalitim</strong> — 'Wisdom strengthens the wise more than ten rulers in a city.' <em>Ta'oz</em> (H5810, to make strong/give strength) from <em>azaz</em> (strong) — wisdom as a source of strength surpassing political power. <em>Asarah shalitim</em> (ten rulers) — ten is a round number for totality; 'ten rulers in a city' describes comprehensive human authority. The comparison: wisdom exceeds the collective power of an entire city's governing body. This is a genuine <em>yitron</em> for wisdom within the under-sun frame.</p>",
        "20": "<p><strong>Ki adam ein tzadiq ba-aretz asher ya'aseh-tov ve-lo yecheta</strong> — 'Indeed, there is no righteous person on earth who always does good and never sins.' The verse is the OT's clearest summary statement of universal human sinfulness as a wisdom observation. <em>Ein tzadiq</em> (no righteous person) — absolute negation. The Teacher does not say people are mostly bad; he says that the category of the perfectly consistent righteous person is empty. This verse becomes a foundation for Paul's extended argument in Romans 3:10-12 (citing Ps 14:1-3 and related texts) that 'no one is righteous, no not one' — the NT reads this as the anthropological premise that makes the gospel necessary.</p>",
        "21": "<p><strong>Gam le-khol-ha-devarim asher yedaberu al-titen libbekha</strong> — 'Do not pay attention to everything people say.' The practical counsel: selective hearing is wisdom. Not every comment, criticism, or opinion deserves to be taken to heart. <em>Asher lo-tishma et-avdekha meqallelekha</em> — 'or you may hear your own servant cursing you.' The specific danger of over-attending to speech: one hears things one would rather not know. <em>Qalal</em> (to curse/speak lightly of) — the servant's contemptuous speech about the master. The counsel is not to cultivate ignorance but to maintain equanimity rather than obsessively monitoring what others say.</p>",
        "22": "<p><strong>Ki gam-pa'amim rabbot yede'a libbekha asher gam-atah qillalta acherim</strong> — 'For your own heart knows that you too have cursed others many times.' The counter-accusation is the corrective: the person outraged by their servant's cursing knows from their own experience that they have done the same. The <em>lev</em> (heart) that knows this is the seat of self-knowledge. The verse is a practical argument from moral parity: if you have done the same thing, your outrage at being its object is disproportionate. The wisdom is not cynicism but self-awareness.</p>",
        "23": "<p><strong>Kol-zot nissiti ve-hakhmah</strong> — 'All this I have tested by wisdom.' <em>Nisah</em> (to test/try) — the same verb as 2:1 for the pleasure experiment. The Teacher has used wisdom as his instrument throughout. <em>Amarti echekhemah</em> — 'I said, &#8220;I will be wise.&#8220;' The aspiration is stated as past tense: he sought comprehensive wisdom. <em>Ve-hi rachaqah mimmenni</em> — 'but wisdom was far from me.' The confession of failure: after the entire Royal Experiment and the wisdom observations of ch 7, the Teacher acknowledges that full wisdom has eluded him. The wisdom that would resolve the <em>hevel</em> paradox is precisely what 'under the sun' existence cannot provide.</p>",
        "24": "<p><strong>Rachoq mah-shehayah ve-amoq amoq mi yimtza'ennu</strong> — 'Whatever exists is far off and utterly deep — who can discover it?' The double superlative <em>amoq amoq</em> (deep, deep) indicates unfathomable depth. <em>Mi yimtza'ennu</em> (who can find it?) — the epistemological limit of all wisdom. The Teacher's conclusion at the midpoint of his extended investigation: reality is too deep for comprehensive knowledge within the 'under the sun' frame. This is not nihilism but honest admission of creaturely limitation.</p>",
        "25": "<p><strong>Saboti ani ve-libbi lada'at ve-latour ve-vaqesh hokhmah ve-cheshbon</strong> — 'I turned my mind to know, to investigate, and to seek out wisdom and the explanation of things.' The four verbs (<em>yada</em>=to know, <em>tur</em>=to explore/scout, <em>baqash</em>=to seek, from <em>cheshbon</em>=account/explanation) accumulate to describe comprehensive intellectual effort. <em>Ve-lada'at rish'at kesel ve-ha-sikhlet holalot</em> — 'to know that wickedness is folly and that foolishness is madness.' The terminal definitions: wickedness reduces to folly; folly to madness. The three-level degradation: wickedness → folly → madness.</p>",
        "26": "<p><strong>U-motze ani mar mi-mavet et-ha-ishah</strong> — 'And I find more bitter than death the woman whose heart is a trap.' <em>Mar mi-mavet</em> (more bitter than death) — a comparative stronger than any other in the book: this is the most bitter thing the Teacher has found, exceeding even the worst of the <em>hevel</em> observations. The woman described here is not women-in-general; she is the Folly figure of Proverbs 5-7 — the seductress whose heart is a trap (<em>metzodim</em>, net/trap) and hands are chains. <em>Tov lifnei ha'Elohim yimalet mimenah ve-chote yillaked bah</em> — 'the one who pleases God escapes her, but the sinner is caught by her.' The escape/capture language mirrors the trap imagery: those who please God are not caught; the sinner is ensnared.</p>",
        "27": "<p><strong>Re'eh zeh matzati amar Qohelet achat le-achat limtzo cheshbon</strong> — 'Here is what I found, says the Preacher, adding one thing to another to find the result.' The Teacher steps back from the investigation to describe his method: accumulating evidence (<em>achat le-achat</em>, one by one) to reach a <em>cheshbon</em> (account/reckoning/sum). <em>Amar Qohelet</em> — 'says Qohelet' — the third-person reference to the Teacher within his own speech is unusual; it may mark a moment of reflective distance, as if the Teacher observes himself in the act of investigation.</p>",
        "28": "<p><strong>Asher od-biqshah nafshi ve-lo matzati</strong> — 'I have continually searched but not found.' The verb <em>biqshah</em> (seeking, H1245) used for persistent, ongoing search. <em>Adam echad me-elef matzati ve-ishah be-khol-elleh lo matzati</em> — 'one man in a thousand I have found, but not one woman among all these.' The verse has generated considerable controversy: it appears to express a misogynistic conclusion, but its context (the Woman-Folly figure of v.26 and the Proverbs 1-9 background) suggests the Teacher is making an observation about the extreme rarity of wisdom rather than a sweeping judgment about women. In the wisdom tradition, the woman who fears YHWH is praised (Prov 31:30), but the temptress who is more bitter than death (v.26) is a specific category. The one-in-a-thousand and zero-in-all-women figures are extreme rhetorical statements within the investigation.</p>",
        "29": "<p><strong>Ledad ra'eh zeh matzati asher asah ha'Elohim et-ha'adam yashar</strong> — 'This alone I have found: God made human beings upright.' <em>Yashar</em> (H3477, upright/straight) — the created condition of humanity before the fall. The contrast is with <em>me'uvat</em> (crooked/bent) from 1:15: what God made straight, sin has bent. <em>Ve-hemah biqqeshu chishevonot rabbim</em> — 'but they have gone in search of many devices.' <em>Chishevonot</em> (H2810, devices/schemes/calculations) — the word is the plural of <em>cheshbon</em>: the Teacher's own investigative method is now used pejoratively for the human search for alternative designs to God's straight creation. The paradox: the human capacity for investigation (<em>cheshbon</em>) is precisely what has bent humanity away from the <em>yashar</em> state in which it was created.</p>"
    },
    "8": {
        "1": "<p><strong>Mi khe-chakham u-mi yode'a pesher davar</strong> — 'Who is like the wise man? Who else knows the meaning of a matter?' <em>Pesher</em> (H6592, interpretation/meaning) is an Aramaic loanword that appears in later Hebrew (also Dan 2:4-7:28 throughout; and in the Dead Sea Scrolls' pesher-commentaries). Its presence here is one of the linguistic markers suggesting a Persian-period date for Ecclesiastes' final form. <em>Chokhemat adam ta'ir panav</em> — 'a person's wisdom brightens his face.' <em>Ya'ir</em> (brightens/illuminates) — the face lit by wisdom is the visible sign of inner understanding. <em>Ve-az panav yeshuneh</strong> — 'and transforms its harsh expression' — literally 'the strength/boldness of his face is changed.' Wisdom changes not just what one knows but how one appears: the harsh or defensive expression softens under wisdom's light.</p>",
        "2": "<p><strong>Ani pi-melek shmor</strong> — 'I counsel you: keep the king's command.' The abrupt opening in Hebrew — 'I' + 'the king's mouth/command' + 'keep' — is elliptical. The MKT supplies 'counsel you' for clarity. <em>Ve-al divrat shevuat Elohim</em> — 'and do so because of your oath before God.' The counsel to royal obedience is grounded not in the king's power alone but in the oath sworn before God — a theological foundation for political compliance. This connects to the covenant context of royal service in Israel.</p>",
        "3": "<p><strong>Al-tibahal mi-panav telekh</strong> — 'Do not be in a hurry to leave the king's presence.' <em>Bahal</em> (hasty/dismayed) — the third use of this word in Ecclesiastes (5:2; 7:9): hasty withdrawal from the king, like hasty speech before God (5:2) or hasty anger (7:9), is a form of rashness. <em>Al-ta'amod be-davar ra</em> — 'do not persist in a bad cause.' The counsel is practical political wisdom: do not rush out of the king's sight, and do not lock into a bad position. <em>Ki kol-asher yachpots ya'aseh</em> — 'for he does whatever he wants.' The king's absolute will is the given context within which the courtier must navigate.</p>",
        "4": "<p><strong>Ba'asher devar-melek shilton</strong> — 'For the king's word is absolute.' <em>Shilton</em> (H7983, power/dominion/authority) — a word used in the Aramaic portions of Daniel for royal sovereignty. <em>U-mi yomar-lo mah-ta'aseh</em> — 'and no one can say to him, &#8220;What are you doing?&#8220;' The rhetorical question borrows language from Job 9:12 ('who can say to him, &#8220;What are you doing?&#8220;') where it describes God's absolute sovereignty. The Teacher uses the divine-sovereignty formula for the king — not to equate king with God, but to describe the practical absolutism of royal power within the sub-eschatological frame.</p>",
        "5": "<p><strong>Shomer mitzvah lo yeda davar ra</strong> — 'Whoever obeys his command will come to no harm.' The practical promise: compliance brings safety, not because the king is always just, but because defiance of absolute power is self-destructive. <em>Ve-et u-mishpat yeda lev chakham</em> — 'and the wise heart will know the proper time and way.' <em>Et u-mishpat</em> (time and judgment/method) — the two-part discernment that wisdom provides: when to act (<em>et</em>) and how to act (<em>mishpat</em>). The <em>et</em> connects to the times poem of ch 3; wisdom knows which time calls for what response.</p>",
        "6": "<p><strong>Ki le-khol-chefetz yesh et u-mishpat</strong> — 'For every purpose has its proper time and method.' <em>Chefetz</em> (H2656, purpose/delight/matter) — the word from 3:1's introduction to the times poem. The <em>et</em> (time) and <em>mishpat</em> (method/judgment) pair recurs: every matter has both its moment and its appropriate mode. <em>Ki ra'at ha'adam rabbah alav</em> — 'though a person's trouble weighs heavily on him.' The contextual complication: knowing that there is a proper time and way is not the same as knowing when and how in the specific situation. The trouble of the human condition is precisely this gap between principle and application.</p>",
        "7": "<p><strong>Ki einennu yode'a mah-sheyih'yeh</strong> — 'For no one knows what is coming.' <em>Mi yode'a</em> (who knows?) / <em>einennu yode'a</em> (he does not know) — the epistemological limit formula recurs: the future is opaque. <em>Ki ka'asher yih'yeh mi yagid-lo</em> — 'and who can tell him how it will come?' The double question structure: not just what will happen, but how it will come. The king's power (vv.3-4) does not exempt the king from this epistemological limit; even the one who 'does whatever he wants' cannot know the future.</p>",
        "8": "<p><strong>Ein adam shaliyt ba-ruach likhloa et-ha-ruach</strong> — 'No one has power over the life-breath to restrain it.' The word <em>ruach</em> (H7307, spirit/breath/wind) is the key word here: in the context of death, <em>ruach</em> is the life-breath that God gives and takes (3:21; Gen 2:7; 6:17; Job 34:14-15). No human <em>shaliyt</em> (ruler/controller) has authority over this <em>ruach</em>. <em>Ve-ein shilton be-yom ha-mavet</em> — 'and no one has power over the day of death.' <em>Shilton</em> reappears (v.4: the king's <em>shilton</em>); neither the absolute monarch nor anyone else has <em>shilton</em> over death's timing. <em>Ve-ein mishlachat ba-milchamah</em> — 'there is no release from that battle.' The war metaphor: death is a battle in which the soldier cannot be discharged or furloughed.</p>",
        "9": "<p><strong>Et-kol-zeh ra'iti ve-naton et-libbi le-khol-ma'aseh asher na'asah tahat hashemesh</strong> — 'All this I observed while applying my mind to everything done under the sun.' The empirical formula marks the transition to a new social observation. <em>Et asher shalat ha'adam ba'adam le-ra' lo</em> — 'a time when one person dominates another to their own harm.' The verb <em>shalat</em> (to rule/control) — the same word as the king's <em>shilton</em> (vv.4, 8): now the king's type of absolute control is exercised by one person over another, with harmful results. The <em>le-ra' lo</em> (to his own harm) is ambiguous: to the oppressor's harm, or to the oppressed's harm? The ambiguity may be intentional.</p>",
        "10": "<p><strong>U-ve-khein ra'iti resha'im qeburim u-va'u</strong> — 'Then I saw the wicked buried.' The observation of wicked people receiving honorable burial: <em>u-va'u</em> (and they went/came) from <em>bo</em> — 'they came and went.' <em>U-min-maqom qadosh yehalekhu</em> — 'they had gone from the sacred place' — possibly the temple or a sacred assembly where they had appeared religious. <em>Va-yishtakkehu va-'ir khen asher ken-pa'alu</em> — 'and they were soon forgotten in the very city where they had done such things' — the wicked receive burial (honor) and then are forgotten in the city of their crimes. <em>Gam-zeh havel</em> — the verdict: the apparent dignity of the wicked's burial and the forgetting of their crimes in the same city are both instances of <em>hevel</em>.</p>",
        "11": "<p><strong>Asher ein-na'asah fitgam ma'aseh ha-ra'ah mehera</strong> — 'When the sentence for a wrong is not carried out quickly.' The word <em>fitgam</em> (H6599, sentence/decree/verdict) is an Aramaic loanword used in Ezra and Esther for royal decrees. Its appearance in Ecclesiastes is another Persian-period linguistic marker. <em>Al-kein male lev benei ha-adam bahem la'asot ra</em> — 'the human heart is emboldened to do evil.' <em>Male lev</em> (the heart is filled/full) — when swift judicial response to wrongdoing is absent, the human heart fills with confidence to continue wrongdoing. The verse is a precise observation about deterrence: justice delayed enables sin emboldened.</p>",
        "12": "<p><strong>Asher chote oseh ra me'at ve-ma'arikh lo</strong> — 'Although a sinner does evil a hundred times and still lives long.' <em>Me'at</em> (a hundred times) — the sinner's multiplied wrongdoing without apparent consequence. <em>Ki gam-yode'a ani asher yih'yeh tov le-yire'ei ha'Elohim asher yir'u milfanav</em> — 'I know that it will go well with those who fear God, who stand in awe before him.' Despite the evidence of delayed justice and wicked longevity, the Teacher affirms confidence in the God-fearer's outcome. The phrase <em>yir'u milfanav</em> (stand in awe before him) intensifies <em>yire'ei ha'Elohim</em> (those who fear God): it is not formal religion but personal reverence.</p>",
        "13": "<p><strong>Ve-tov lo yih'yeh la-rasha</strong> — 'But it will not go well with the wicked.' The simple negation answers v.12's positive. <em>Ve-lo ya'arikh yamim ka-tzel</em> — 'and their days will not lengthen like a shadow.' The <em>tzel</em> (shadow) — connected to the wisdom-shadow of 7:12 (<em>be-tzel ha-chakhmah</em>): wisdom provides protective shade; the wicked's days are not extended like a protective shadow. <em>Asher einennu yare' mi-lifnei Elohim</em> — 'because they do not fear God.' The absence of <em>yir'at Elohim</em> (fear of God) is the identifying characteristic of the wicked: not specific sins but the foundational orientation away from God.</p>",
        "14": "<p><strong>Yesh-hevel asher na'asah al-ha'aretz</strong> — 'There is a futility that occurs on earth.' The Teacher's flat observation of injustice in outcomes: <em>yesh tzadiqim asher magiy'a alehem ke-ma'aseh ha-resha'im</em> — 'the righteous get what the wicked deserve.' The moral categories (<em>tzadiq</em>, righteous; <em>rasha</em>, wicked) that the wisdom tradition uses to predict outcomes are here inverted in observed experience. <em>Ve-yesh resha'im shemagi'a alehem ke-ma'aseh ha-tzadiqim</em> — 'and the wicked get what the righteous deserve.' The double inversion is complete. <em>Amarti shegam-zeh havel</em> — 'I said that this too is futility.' The Teacher does not explain or rationalize the injustice; he names it <em>hevel</em> and continues.</p>",
        "15": "<p><strong>Ve-shivachthi ani et-ha-simha</strong> — 'So I commend joy.' <em>Shivach</em> (H7623, to praise/commend/declare fortunate) — the same verb as 4:2 ('I counted the dead more fortunate than the living'). Here it is used positively: the Teacher publicly commends joy as the response to the observed injustice of vv.12-14. <em>Asher ein-tov la'adam tahat hashemesh ki im-le'ekhol ve-lishtot ve-lismoch</em> — 'for there is nothing better for people under the sun than to eat and drink and be glad.' The carpe diem formula recurs in its fullest form. <em>Ve-hu yilavennu ba-amalo</em> — 'this accompanies them in their work through all the days of life that God has given them under the sun' — joy is not an escape from work but the companion of work throughout the God-given life.</p>",
        "16": "<p><strong>Ka'asher natati et-libbi lada'at chokhmah</strong> — 'When I applied my mind to know wisdom.' The Teacher's empirical method statement before the conclusion of this section. <em>Ve-lir'ot et-ha-inyan asher na'asah al-ha'aretz</em> — 'and to observe all the activity carried on upon the earth.' <em>Inyan</em> (business/occupation/activity) — recurs from 1:13 for the 'unhappy business' of human investigation. <em>Ki gam ba-yom u-va-layla shena be-einav einennu ro'eh</em> — 'for neither day nor night do people see sleep.' The extreme of wakeful investigation: not even sleep interrupts the effort to understand. This is the hyperbolic description of comprehensive inquiry.</p>",
        "17": "<p><strong>Ve-ra'iti et-kol-ma'aseh ha'Elohim ki lo-yuchal ha'adam limtzo et-ha-ma'aseh asher na'asah tahat hashemesh</strong> — 'Then I saw all the work of God — that no one can discover what is done under the sun.' The phrase <em>kol ma'aseh ha'Elohim</em> (all the work of God) is the comprehensive divine activity that the Teacher claims no one can fully discover. <em>Be-sheliyiqchal ha'adam la'amol levaqesh ve-lo yimtza</em> — 'no matter how much one labors in searching, they will not find it out.' <em>Amal le-baqesh</em> (labor in searching) — the word <em>amal</em> applied to the activity of inquiry: the labor of investigation itself is subject to the same futility-verdict as physical labor. <em>Ve-gam im-yomar he-chakham lada'at lo yuchal limtzo</em> — 'even if the wise claim to know, they cannot find it out.' Even the self-proclaimed expert is bounded by the same epistemological limit. This is the Teacher's most comprehensive statement of the limits of 'under the sun' wisdom.</p>"
    },
    "9": {
        "1": "<p><strong>Ki et-kol-zeh natati el-libbi u-levarer et-kol-zeh</strong> — 'I laid all this to heart and considered it carefully.' The verb <em>berar</em> (H1305, to sift/test/purify/clarify) — the same word as 3:18's 'God is testing them'; here the Teacher applies the testing/clarifying process to his own observations. <em>Asher ha-tzadiqim ve-ha-chakhamim u-ma'aseihem be-yad ha'Elohim</em> — 'that the righteous and the wise and all they do are in God's hands.' Despite all the observed inversions and futilities, this is the Teacher's theological anchor: all humans and their works are in God's hands (<em>yad ha'Elohim</em>). <em>Gam-ahavah gam-sin'ah ein yode'a ha'adam</em> — 'yet no one knows whether love or hatred awaits them.' Even within God's hands, the specific destiny — divine love or divine anger — is unknown to the human. The epistemological limit applies even to the most basic question of one's standing before God.</p>",
        "2": "<p><strong>Hakol ka'asher le-khol miqreh echad la-tzadiq vela-rasha</strong> — 'The same fate comes to everyone: to the righteous and to the wicked.' <em>Miqreh echad</em> (one fate/event) — the key phrase from 2:14 and 3:19 returns: the common death that equalizes all distinctions. The Teacher now catalogs the pairs that are equalized: righteous/wicked, good/clean/unclean, sacrificer/non-sacrificer, those who swear oaths/those who avoid them. The catalog is comprehensive — every social and religious distinction collapses at death. <em>Ha-tov ka-chote</em> — 'the good person and the sinner' — the broadest moral categories, both meeting the same <em>miqreh</em>.</p>",
        "3": "<p><strong>Zeh ra be-kol asher-na'asah tahat hashemesh ki-miqreh echad le-khol</strong> — 'This is the evil in everything done under the sun: one fate comes to all.' The <em>ra</em> (evil) of the one fate is the Teacher's moral assessment of death's indiscriminate character. <em>Ve-gam lev benei ha-adam male ra</em> — 'Moreover, people's hearts are full of evil.' This is not a new observation but its intensification: the <em>ra</em> (evil) of the one fate corresponds to the <em>ra</em> (evil) in human hearts. <em>Ve-holeylot be-lehavhem be-chayyeihem</em> — 'and madness fills them throughout their lives.' <em>Holalot</em> (madness/raving) from <em>halal</em> (to be mad/praise wildly) — the human condition under the sun is madness. <em>Ve-acharav el-ha-metim</em> — 'and after that, they go to the dead.' The simple temporal statement: after life, death. No elaboration, no comfort.</p>",
        "4": "<p><strong>Ki mi asher yevuchar el kol-ha-chayyim yesh bitachon</strong> — 'Anyone still among the living has hope.' The word <em>bitachon</em> (H986, hope/trust/confidence) — the same root as <em>batach</em> (to trust/rely on), frequently a trust-in-God word (Ps 22:4-5; Prov 3:5). Here it describes the hope that belongs to the living simply by virtue of being alive. <em>Ki-kelev chai hu tov min-ha-ari ha-met</em> — 'for a living dog is better off than a dead lion.' The proverb inverts status: the dog was the most despised animal in the ANE; the lion the most noble. But alive/dead reverses the hierarchy completely. Life — any life — has the advantage of <em>bitachon</em>; death has none.</p>",
        "5": "<p><strong>Ki ha-chayyim yod'im she-yamutu</strong> — 'The living know that they will die.' This knowledge of one's own mortality is the human's unique self-awareness — the animal equivalent of the <em>olam</em> planted in the human heart (3:11). <em>Ve-ha-metim einam yod'im me'umah</em> — 'but the dead know nothing.' The Teacher's statement about the dead's knowledge is within his 'under the sun' epistemological frame — he does not claim to know what lies beyond death (cf. 3:21: 'who knows?'). From the perspective of earthly existence, the dead are absent from everything that happens under the sun. <em>Ve-ein od lahem sakar</em> — 'they have no further reward' — <em>sakar</em> (H7939, wage/reward) — the dead receive no more compensation for their former work.</p>",
        "6": "<p><strong>Gam ahavah gam sin'ah gam qin'atam kebar avadah</strong> — 'Their love, their hatred, and their envy have all vanished.' The three driving forces of human social life — love, hatred, envy (<em>qin'ah</em>, 4:4) — have perished (<em>avad</em>, to be lost/destroyed) with the dead. <em>Ve-chelek ein-lahem od le-olam</em> — 'they have no share any longer in anything that happens under the sun.' <em>Chelek</em> (H2506, portion/share/lot) — the same word as <em>helqi</em> (my portion, 2:10): the dead have no portion in the ongoing life of the world. This is not a statement about the afterlife but about the dead's absence from earthly participation.</p>",
        "7": "<p><strong>Lekh ekhol be-simhah lachmekha</strong> — 'Go, eat your food with gladness.' The imperatives of the carpe diem counsel are now at their most direct: <em>lekh</em> (go), <em>ekhol</em> (eat), <em>shtei</em> (drink — from the next line). <em>Ki-kebar ratzah ha'Elohim et-ma'asekha</em> — 'for God has already approved what you do.' <em>Ratzah</em> (H7521, to be pleased with/accept/approve) — the theological grounding of the carpe diem: God's prior approval of the person's enjoyment is already secured. The 'already' (<em>kebar</em>) is significant: the divine approval is not conditional on finding the right moments; it is established in advance. The person who eats gladly is not choosing against God's will — they are acting within it.</p>",
        "8": "<p><strong>Be-khol-et yih'yu begadekha levanim</strong> — 'Let your clothing always be fresh and white.' <em>Levanim</em> (white) — the garments of celebration and purity in the ANE (also connected to priestly garments and the eschatological white garments of Rev 3:5; 7:9). <em>Ve-shemen al-roshekha al-yechsar</em> — 'and let your head not lack for oil.' Anointing oil on the head was a sign of festivity and honor (Ps 23:5; 45:7; Amos 6:6). The counsel: present yourself as a celebrant at the feast of life, not as a mourner withholding joy. The carpe diem posture is a bodily as well as internal reality.</p>",
        "9": "<p><strong>Re'eh chayyim im-ha-ishah asher-ahavta</strong> — 'Enjoy life with the wife you love.' <em>Re'eh</em> (see/enjoy/find good in) — the Teacher's characteristic verb now applied to the marital relationship: enjoy the life you share with the wife you love. <em>Kol-yemei chayyei havlekha</strong> — 'throughout all your fleeting days under the sun — all the days of your vapor.' The phrase <em>chayyei havlekha</em> (the life of your vapor) — used in 6:12 for the duration of the vapor-life. <em>Ki hu helqekha ba-chayyim</em> — 'for that is your portion in this life.' <em>Helqekha</em> — the positive counsel's key word: the marital joy is the <em>helq</em> that actually belongs to the person, as real a portion as any material acquisition.</p>",
        "10": "<p><strong>Kol asher timtza yadkha la'asot be-kochakha aseh</strong> — 'Whatever your hand finds to do, do it with all your strength.' The intensifying phrase <em>be-kochakha</em> (with your strength/power) — the same radical intensity with which the Teacher tested wisdom and pleasure is now applied to the carpe diem counsel: do fully what is before you. <em>Ki ein ma'aseh ve-cheshbon ve-da'at ve-chakhmah bi-she'ol asher atah holekh sham</em> — 'there is no work, no planning, no knowledge, no wisdom in the grave — where you are going.' The fourfold negation in Sheol (<em>ma'aseh</em>=work, <em>cheshbon</em>=planning/reckoning, <em>da'at</em>=knowledge, <em>chakhmah</em>=wisdom) is the counterpart to the Teacher's fourfold investigative verbs in 8:16. Everything that constitutes the active life under the sun is absent in Sheol: urgency is therefore appropriate now.</p>",
        "11": "<p><strong>Shavti ve-ra'oh tahat hashemesh</strong> — 'Again I observed that under the sun.' The empirical formula introduces the famous observation about time and chance. <em>Lo la-qallim ha-merutz ve-lo la-giborim ha-milchamah ve-gam lo la-chakhamim lechem</em> — 'the race is not won by the swift, nor the battle by the strong, nor bread by the wise.' Three pairs of expectation reversed: the swift runner, the mighty warrior, the wise person — none of these attributes guarantees the corresponding outcome. <em>Ki et ve-fega yiqreh et-kulam</em> — 'rather, time and chance happen to them all.' <em>Et</em> (time/moment) + <em>fega</em> (H6294, occurrence/chance/accident) — the two-word phrase for the element of contingency that disrupts predictable outcomes. <em>Fega</em> is a rare word (used only here in the OT); its rarity emphasizes the singularity of the observation.</p>",
        "12": "<p><strong>Ki gam lo-yeda ha'adam et-ito</strong> — 'No one knows when their hour will come.' <em>Ito</em> (his time/hour) — the appointed moment that <em>et ve-fega</em> (v.11) unpredictably delivers. <em>Ke-dagim she-ne'achazim be-metzodah ra'ah</em> — 'as fish are caught in a cruel net.' <em>Metzodah</em> (H4686, net/hunting device) — the same word used for the wicked woman's heart in 7:26 (a trap). The net/trap metaphor: the fish does not know when the net will close; the bird does not know when the snare will spring. <em>Ke-hem yukashim livnei ha-adam le-et ra'ah</em> — 'so people are trapped at some evil moment when it suddenly falls upon them.' <em>Et ra'ah</em> (evil time/hour) — the moment of catastrophe that arrives unexpectedly, as death arrives unexpectedly in the human condition.</p>",
        "13": "<p><strong>Gam-zot ra'iti chakhmah tahat hashemesh ve-gedolah hi elai</strong> — 'I also observed this example of wisdom under the sun, and it struck me as remarkable.' The Teacher introduces a narrative illustration. <em>Ve-gedolah hi elai</em> — 'it struck me as remarkable' — literally 'and it was great to me.' The word <em>gedolah</em> (great/remarkable) signals that what follows is a significant case study, despite its brevity. The narrative of the poor wise man who saved a city and was forgotten is one of Ecclesiastes' most penetrating parables of wisdom's limits.</p>",
        "14": "<p><strong>Ir qetanah u-va'anashim bah me'at</strong> — 'There was a small city with few people in it.' The smallness of the city and the fewness of its people establish the vulnerability of what is defended. <em>U-va-eleyha melek gadol</strong> — 'and a powerful king came against it.' The asymmetry: a great king against a small city. <em>Ve-savav otah u-vanah aleha metzodim gedolim</em> — 'besieged it, and built great siege works around it.' <em>Metzodim gedolim</em> (great siege works) — the full military investment of a major power against a small city. The situation appears hopeless.</p>",
        "15": "<p><strong>U-matza vah ish misken chakham</strong> — 'But a poor wise man was found in the city.' <em>Misken</em> (H4542, poor/destitute) — a word unique to Ecclesiastes in the OT; it designates poverty as a social status. <em>U-milat-hu et-ha'ir be-chakhmato</em> — 'and by his wisdom he saved it.' The wisdom of the poor man accomplishes what military strength could not. <em>Ve-adam lo zakar et-ha'ish ha-misken ha-hu</em> — 'yet no one remembered that poor man afterward.' The memorial failure is the point: the poor wise man who saved the city receives no <em>zikaron</em> (remembrance). The absence of memorial repeats the pattern of 1:11 (no remembrance of former people) but now it is unjust forgetting, not merely the structural limit of memory.</p>",
        "16": "<p><strong>Va-omar ani tovah chakhmah mi-gevurah</strong> — 'Then I concluded: wisdom is better than strength.' The <em>tov min</em> comparison is the Teacher's verdict: the poor wise man's salvation of the city is conclusive evidence of wisdom's superiority over force. <em>Ve-chokhemat ha-misken bezuyah u-devarav einam nishma'im</em> — 'But the poor man's wisdom is despised and his words go unheard.' The tension is not resolved: wisdom is objectively better, yet practically despised when it resides in poverty. The <em>bezuyah</em> (despised) echoes the royal treatment of David's wisdom before he was king (1 Sam 17:33). Poverty is the social condition that makes wisdom invisible.</p>",
        "17": "<p><strong>Divrei chakhamim be-nachat nishma'im</strong> — 'Words spoken quietly by the wise carry more weight.' <em>Be-nachat</em> (H5183, in quietness/calmly) — <em>nachat</em> appeared at 4:6 and 6:5 for the rest that is better than restless striving. Now it describes the delivery mode of wisdom: quietly, without shouting. <em>Mi-ze'aqat moshe ba-kesilim</em> — 'than the shouting of a ruler among fools.' The ruler (<em>moshel</em>, H4910) whose audience is fools produces shouting, not wisdom. The contrast: quiet speech among attentive hearers outweighs loud speech among fools who do not hear.</p>",
        "18": "<p><strong>Tovah chakhmah mi-klei milchamah</strong> — 'Wisdom is better than weapons of war.' The final <em>tov min</em> comparison of this section extends the poor wise man's lesson to a principle. <em>Ve-choteh echad ye'abed tovah harbeh</em> — 'but one fool can undo a great deal of good.' <em>Ye'abed</em> (H6) from <em>abad</em> (to destroy/cause to perish) — the single sinner's destructive capacity. The asymmetry is deliberately stark: wisdom of many is better than weapons of many, but one fool can destroy what wisdom builds. This is the Teacher's unsentimental conclusion about the fragility of wisdom's achievements within the 'under the sun' frame — a single point of failure can unravel everything.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', 'ecclesiastes')
    merge_comm(existing, ECCLESIASTES)
    save_comm('mkt-original', 'ecclesiastes', existing)
    print('Ecclesiastes 5-9 mkt-original written.')

if __name__ == '__main__':
    main()
